output.sparql:
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT ?clock_tower ?clock_tower_label WHERE {
  ?clock_tower wdt:P31 wd:Q143152 .
  ?clock_tower wdt:P17 ?country .
  ?country wdt:P46 ?continent .
  FILTER(?continent != wd:Q46 && ?continent != wd:Q19 && ?continent != wd:Q712)
  OPTIONAL {
    ?clock_tower rdfs:label ?clock_tower_label .
    FILTER(LANG(?clock_tower_label) = "en")
  }
}

